terraform_files.provider.tf:
terraform {
  required_version = ">= 1.6.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }

  backend "s3" {
    bucket         = "aegis-terraform-state"
    key            = "prod/terraform.tfstate"
    region         = "us-east-1"
    encrypt        = true
    dynamodb_table = "terraform-locks"
  }
}

provider "aws" {
  region = var.aws_region

  default_tags {
    tags = {
      ManagedBy   = "Terraform"
      Project     = "aegis-migration"
      Environment = var.environment
      MigratedBy  = "AegisMigrationFactory"
    }
  }
}

terraform_files.variables.tf:
variable "aws_region" {
  description = "AWS region for resource deployment"
  type        = string
  default     = "us-east-1"
}

variable "environment" {
  description = "Environment name (production, staging, dev)"
  type        = string
  default     = "production"
}

variable "ami_id" {
  description = "AMI ID for EC2 instances"
  type        = string
  default     = "ami-0c55b159cbfafe1f0"
}

variable "vpc_cidr" {
  description = "CIDR block for VPC"
  type        = string
  default     = "10.0.0.0/16"
}

variable "public_subnet_cidr" {
  description = "CIDR block for public subnet"
  type        = string
  default     = "10.0.1.0/24"
}

variable "private_subnet_cidr" {
  description = "CIDR block for private subnet"
  type        = string
  default     = "10.0.2.0/24"
}

variable "db_password" {
  description = "Password for RDS database"
  type        = string
  sensitive   = true
}

variable "ssh_key_name" {
  description = "EC2 Key Pair name for SSH access"
  type        = string
  default     = "aegis-prod-key"
}

terraform_files.main.tf:
# ============================================================================
# Aegis Migration Factory — Translated AWS Infrastructure
# Migrated from GCP by Aegis AI Migration Pipeline
# ============================================================================

# --- VPC (from google_compute_network.vpc) ---
resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "prod-vpc"
  }
}

# --- Public Subnet (from google_compute_subnetwork.public_subnet) ---
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.public_subnet_cidr
  availability_zone       = "${var.aws_region}a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# --- Private Subnet (from google_compute_subnetwork.private_subnet) ---
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = var.private_subnet_cidr
  availability_zone = "${var.aws_region}b"

  tags = {
    Name = "private-subnet"
  }
}

# --- Internet Gateway ---
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "prod-igw"
  }
}

# --- Security Group (from google_compute_firewall.allow_http) ---
resource "aws_security_group" "web" {
  name_prefix = "web-sg-"
  vpc_id      = aws_vpc.main.id
  description = "Allow HTTP/HTTPS inbound traffic"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "HTTP"
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "HTTPS"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web-security-group"
  }
}

# --- Security Group (from google_compute_firewall.allow_internal) ---
resource "aws_security_group" "internal" {
  name_prefix = "internal-sg-"
  vpc_id      = aws_vpc.main.id
  description = "Allow internal traffic"

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
    description = "Internal TCP"
  }

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "udp"
    cidr_blocks = ["10.0.0.0/8"]
    description = "Internal UDP"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "internal-security-group"
  }
}

# --- App Server EC2 (from google_compute_instance.app_server) ---
resource "aws_instance" "app_server" {
  ami                    = var.ami_id
  instance_type          = "m5.xlarge"
  key_name               = var.ssh_key_name
  subnet_id              = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.web.id, aws_security_group.internal.id]
  iam_instance_profile   = aws_iam_instance_profile.app_server.name

  root_block_device {
    volume_size = 50
    volume_type = "gp3"
    encrypted   = true
  }

  tags = {
    Name = "prod-app-server"
  }
}

# --- Worker EC2 (from google_compute_instance.worker) ---
resource "aws_instance" "worker" {
  ami                    = var.ami_id
  instance_type          = "t3.large"
  subnet_id              = aws_subnet.private.id
  vpc_security_group_ids = [aws_security_group.internal.id]
  iam_instance_profile   = aws_iam_instance_profile.app_server.name

  root_block_device {
    volume_size = 30
    volume_type = "gp3"
    encrypted   = true
  }

  tags = {
    Name = "prod-worker"
  }
}

# --- Elastic IP (from google_compute_address.app_ip) ---
resource "aws_eip" "app" {
  instance = aws_instance.app_server.id
  domain   = "vpc"

  tags = {
    Name = "app-external-ip"
  }
}

# --- RDS PostgreSQL (from google_sql_database_instance.postgres) ---
resource "aws_db_subnet_group" "main" {
  name       = "prod-db-subnet-group"
  subnet_ids = [aws_subnet.private.id, aws_subnet.public.id]

  tags = {
    Name = "prod-db-subnet-group"
  }
}

resource "aws_db_instance" "postgres" {
  identifier           = "prod-postgres-14"
  engine               = "postgres"
  engine_version       = "14.9"
  instance_class       = "db.m5.large"
  allocated_storage    = 100
  storage_type         = "gp3"
  storage_encrypted    = true
  db_name              = "aegis_app"
  username             = "admin"
  password             = var.db_password
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.internal.id]
  multi_az             = true
  deletion_protection  = true
  skip_final_snapshot  = false
  final_snapshot_identifier = "prod-postgres-final"

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"

  tags = {
    Name = "prod-postgres"
  }
}

# --- ElastiCache Redis (from google_redis_instance.cache) ---
resource "aws_elasticache_cluster" "redis" {
  cluster_id           = "app-cache"
  engine               = "redis"
  node_type            = "cache.t3.medium"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  port                 = 6379
  subnet_group_name    = aws_elasticache_subnet_group.main.name
  security_group_ids   = [aws_security_group.internal.id]

  tags = {
    Name = "app-cache"
  }
}

resource "aws_elasticache_subnet_group" "main" {
  name       = "prod-cache-subnet"
  subnet_ids = [aws_subnet.private.id]
}

# --- EKS Cluster (from google_container_cluster.gke_cluster) ---
resource "aws_eks_cluster" "main" {
  name     = "prod-cluster"
  role_arn = aws_iam_role.eks_cluster.arn

  vpc_config {
    subnet_ids         = [aws_subnet.public.id, aws_subnet.private.id]
    security_group_ids = [aws_security_group.internal.id]
  }

  tags = {
    Name = "prod-cluster"
  }
}

resource "aws_eks_node_group" "primary" {
  cluster_name    = aws_eks_cluster.main.name
  node_group_name = "primary-pool"
  node_role_arn   = aws_iam_role.eks_node.arn
  subnet_ids      = [aws_subnet.private.id]
  instance_types  = ["m5.xlarge"]

  scaling_config {
    desired_size = 3
    min_size     = 2
    max_size     = 10
  }

  disk_size = 50

  tags = {
    Name = "primary-node-pool"
  }
}

# --- S3 Buckets (from google_storage_bucket) ---
resource "aws_s3_bucket" "media_assets" {
  bucket        = "aegis-prod-media-assets"
  force_destroy = false

  tags = {
    Name = "media-assets"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "media" {
  bucket = aws_s3_bucket.media_assets.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.main.arn
    }
  }
}

resource "aws_s3_bucket" "backups" {
  bucket        = "aegis-prod-backups"
  force_destroy = false

  tags = {
    Name = "backups"
  }
}

resource "aws_s3_bucket" "logs" {
  bucket        = "aegis-prod-application-logs"
  force_destroy = false

  tags = {
    Name = "application-logs"
  }
}

# --- SNS Topic (from google_pubsub_topic.image_uploads) ---
resource "aws_sns_topic" "image_uploads" {
  name = "image-uploads"

  tags = {
    Name = "image-uploads"
  }
}

# --- SQS Queue (from google_pubsub_subscription.image_sub) ---
resource "aws_sqs_queue" "image_sub" {
  name                       = "image-uploads-sub"
  visibility_timeout_seconds = 30
  message_retention_seconds  = 86400

  redrive_policy = jsonencode({
    deadLetterTargetArn = aws_sqs_queue.image_dlq.arn
    maxReceiveCount     = 5
  })

  tags = {
    Name = "image-uploads-sub"
  }
}

resource "aws_sqs_queue" "image_dlq" {
  name = "image-uploads-dlq"

  tags = {
    Name = "image-uploads-dlq"
  }
}

# --- Lambda (from google_cloudfunctions_function.image_processor) ---
resource "aws_lambda_function" "image_processor" {
  function_name = "image-processor"
  runtime       = "python3.11"
  handler       = "main.process_image"
  memory_size   = 512
  timeout       = 120
  role          = aws_iam_role.lambda_exec.arn

  filename         = "lambda/image-processor.zip"
  source_code_hash = filebase64sha256("lambda/image-processor.zip")

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.media_assets.id
      DB_HOST     = aws_db_instance.postgres.address
    }
  }

  tags = {
    Name = "image-processor"
  }
}

# --- KMS Key (from google_kms_crypto_key.db_key) ---
resource "aws_kms_key" "main" {
  description             = "Aegis encryption key for database and storage"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "aegis-main-key"
  }
}

resource "aws_kms_alias" "main" {
  name          = "alias/aegis-main"
  target_key_id = aws_kms_key.main.key_id
}

# --- IAM Roles ---
resource "aws_iam_role" "app_server" {
  name = "aegis-app-server-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

resource "aws_iam_instance_profile" "app_server" {
  name = "aegis-app-server-profile"
  role = aws_iam_role.app_server.name
}

resource "aws_iam_role" "eks_cluster" {
  name = "aegis-eks-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "eks.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster.name
}

resource "aws_iam_role" "eks_node" {
  name = "aegis-eks-node-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eks_worker" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
  role       = aws_iam_role.eks_node.name
}

resource "aws_iam_role" "lambda_exec" {
  name = "aegis-lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "lambda.amazonaws.com" }
    }]
  })
}

terraform_files.outputs.tf:
output "vpc_id" {
  description = "VPC ID"
  value       = aws_vpc.main.id
}

output "app_server_public_ip" {
  description = "Public IP of the app server"
  value       = aws_eip.app.public_ip
}

output "rds_endpoint" {
  description = "RDS PostgreSQL endpoint"
  value       = aws_db_instance.postgres.endpoint
  sensitive   = true
}

output "redis_endpoint" {
  description = "ElastiCache Redis endpoint"
  value       = aws_elasticache_cluster.redis.cache_nodes[0].address
}

output "eks_endpoint" {
  description = "EKS cluster endpoint"
  value       = aws_eks_cluster.main.endpoint
  sensitive   = true
}

output "media_bucket" {
  description = "Media assets S3 bucket"
  value       = aws_s3_bucket.media_assets.id
}

output "lambda_function_arn" {
  description = "Image processor Lambda ARN"
  value       = aws_lambda_function.image_processor.arn
}
